/**
 * API types — most are generated by `hogli build:openapi` from the Django serializers
 * and live in `./generated/api.schemas.ts`. This module re-exports them under cleaner
 * names and adds the non-generated client-side helpers (assertion type unions, labels,
 * default factories) on top.
 */
import {
    AgenticTestApi,
    AgenticTestRunApi,
    AgenticTestRunStatusEnumApi,
    AgenticTestStatusEnumApi,
} from './generated/api.schemas'

export type AgenticTest = Omit<AgenticTestApi, 'assertions'> & {
    assertions: AgenticTestAssertion[]
}

export type AgenticTestRun = AgenticTestRunApi & {
    // Generated as `unknown` since the serializer uses a JSONField; refine here for the UI.
    output: AgenticTestRunOutput
}

export type AgenticTestStatus = AgenticTestStatusEnumApi
export type AgenticTestRunStatus = AgenticTestRunStatusEnumApi

export type AgenticTestAssertionType = 'url_contains' | 'event_captured'

export interface AgenticTestAssertionUrlContains {
    type: 'url_contains'
    value: string
}

export interface AgenticTestAssertionEventCaptured {
    type: 'event_captured'
    event: string
    within_seconds: number
}

export type AgenticTestAssertion = AgenticTestAssertionUrlContains | AgenticTestAssertionEventCaptured

export interface AgenticTestAssertionResult {
    type: AgenticTestAssertionType
    passed: boolean
    message: string
    config: AgenticTestAssertion
}

export interface AgenticTestRunOutput {
    agent_passed?: boolean
    assertions?: AgenticTestAssertionResult[]
    final_url?: string
    [key: string]: unknown
}

export interface AgenticTestDraft {
    name: string
    description: string
    target_url: string
    prompt: string
    status: AgenticTestStatus
    assertions: AgenticTestAssertion[]
    source_replay_id?: string | null
}

export const ASSERTION_TYPE_LABELS: Record<AgenticTestAssertionType, string> = {
    url_contains: 'URL contains',
    event_captured: 'Event captured',
}

export function defaultAssertion(type: AgenticTestAssertionType): AgenticTestAssertion {
    switch (type) {
        case 'url_contains':
            return { type: 'url_contains', value: '' }
        case 'event_captured':
            return { type: 'event_captured', event: '', within_seconds: 30 }
    }
}
